  ('dietitian-moex-07984', 'dietitian', 'dietitian-moex-099-4665e2ba', 'sub-dietitian-01', NULL, 'single_choice', '社區營養計畫執行需要行銷（marketing），下列何者是行銷4P混和變項（market mix variable）之一？', '["Product", "Practice", "Planning", "Providing"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:48+00:00", "source_pdf_sha1": "f9268d3fe5e7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099130", "c": "108", "s": "500", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公共衛生營養學", "year": "099", "exam_name": "099年第二次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、法醫師、聽力師", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
